import os
import hashlib
import secrets
import time
from functools import wraps
from flask import Flask, request, redirect, url_for, session, render_template_string, flash, g

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['PERMANENT_SESSION_LIFETIME'] = 3600  # 1 hour
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'

# --- Simple in-memory user store (replace with database in production) ---
USERS_DB = {}
SESSIONS_DB = {}

# --- Password hashing utilities ---

def generate_salt():
    return secrets.token_hex(16)

def hash_password(password, salt=None):
    if salt is None:
        salt = generate_salt()
    hashed = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        100000
    )
    return salt, hashed.hex()

def verify_password(password, salt, stored_hash):
    _, computed_hash = hash_password(password, salt)
    return secrets.compare_digest(computed_hash, stored_hash)

# --- Session management ---

def create_session(user_id):
    session_token = secrets.token_urlsafe(64)
    SESSIONS_DB[session_token] = {
        'user_id': user_id,
        'created_at': time.time(),
        'last_active': time.time(),
        'ip_address': request.remote_addr,
        'user_agent': request.headers.get('User-Agent', '')
    }
    return session_token

def validate_session(session_token):
    if session_token not in SESSIONS_DB:
        return None
    
    sess = SESSIONS_DB[session_token]
    
    # Check session expiry (1 hour of inactivity)
    if time.time() - sess['last_active'] > app.config['PERMANENT_SESSION_LIFETIME']:
        destroy_session(session_token)
        return None
    
    # Check absolute session lifetime (24 hours)
    if time.time() - sess['created_at'] > 86400:
        destroy_session(session_token)
        return None
    
    # Update last active time
    sess['last_active'] = time.time()
    
    return sess['user_id']

def destroy_session(session_token):
    SESSIONS_DB.pop(session_token, None)

def destroy_all_user_sessions(user_id):
    tokens_to_remove = [
        token for token, sess in SESSIONS_DB.items()
        if sess['user_id'] == user_id
    ]
    for token in tokens_to_remove:
        del SESSIONS_DB[token]

def cleanup_expired_sessions():
    now = time.time()
    tokens_to_remove = [
        token for token, sess in SESSIONS_DB.items()
        if (now - sess['last_active'] > app.config['PERMANENT_SESSION_LIFETIME']) or
           (now - sess['created_at'] > 86400)
    ]
    for token in tokens_to_remove:
        del SESSIONS_DB[token]

# --- User management ---

def register_user(username, password):
    if not username or not password:
        return False, "Username and password are required."
    
    if len(username) < 3 or len(username) > 50:
        return False, "Username must be between 3 and 50 characters."
    
    if len(password) < 8:
        return False, "Password must be at least 8 characters."
    
    # Normalize username
    username = username.strip().lower()
    
    if username in USERS_DB:
        return False, "Username already exists."
    
    salt, password_hash = hash_password(password)
    USERS_DB[username] = {
        'username': username,
        'salt': salt,
        'password_hash': password_hash,
        'created_at': time.time(),
        'failed_login_attempts': 0,
        'locked_until': 0
    }
    return True, "Registration successful."

def authenticate_user(username, password):
    if not username or not password:
        return False, None
    
    username = username.strip().lower()
    
    if username not in USERS_DB:
        # Perform dummy hash to prevent timing attacks
        hash_password(password)
        return False, None
    
    user = USERS_DB[username]
    
    # Check account lockout
    if user['locked_until'] > time.time():
        remaining = int(user['locked_until'] - time.time())
        return False, f"Account locked. Try again in {remaining} seconds."
    
    if verify_password(password, user['salt'], user['password_hash']):
        user['failed_login_attempts'] = 0
        user['locked_until'] = 0
        return True, None
    else:
        user['failed_login_attempts'] += 1
        # Lock account after 5 failed attempts for 5 minutes
        if user['failed_login_attempts'] >= 5:
            user['locked_until'] = time.time() + 300
            user['failed_login_attempts'] = 0
            return False, "Too many failed attempts. Account locked for 5 minutes."
        return False, None

# --- Rate limiting (simple in-memory) ---

RATE_LIMIT_DB = {}

def check_rate_limit(key, max_requests=10, window=60):
    now = time.time()
    if key not in RATE_LIMIT_DB:
        RATE_LIMIT_DB[key] = []
    
    # Remove old entries
    RATE_LIMIT_DB[key] = [t for t in RATE_LIMIT_DB[key] if now - t < window]
    
    if len(RATE_LIMIT_DB[key]) >= max_requests:
        return False
    
    RATE_LIMIT_DB[key].append(now)
    return True

# --- Login required decorator ---

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_token = session.get('session_token')
        if not session_token:
            flash('Please log in to access this page.', 'warning')
            return redirect(url_for('login', next=request.url))
        
        user_id = validate_session(session_token)
        if user_id is None:
            session.clear()
            flash('Your session has expired. Please log in again.', 'warning')
            return redirect(url_for('login', next=request.url))
        
        g.current_user = user_id
        return f(*args, **kwargs)
    return decorated_function

# --- CSRF Protection ---

def generate_csrf_token():
    if '_csrf_token' not in session:
        session['_csrf_token'] = secrets.token_urlsafe(32)
    return session['_csrf_token']

def validate_csrf_token():
    token = session.get('_csrf_token')
    form_token = request.form.get('_csrf_token')
    if not token or not form_token or not secrets.compare_digest(token, form_token):
        return False
    return True

app.jinja_env.globals['csrf_token'] = generate_csrf_token

# --- Before request hook ---

@app.before_request
def before_request():
    # Cleanup expired sessions periodically (simple approach)
    if secrets.randbelow(100) == 0:  # ~1% chance per request
        cleanup_expired_sessions()
    
    # Set current user if session exists
    session_token = session.get('session_token')
    if session_token:
        user_id = validate_session(session_token)
        g.current_user = user_id
    else:
        g.current_user = None

# --- Security headers ---

@app.after_request
def set_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    response.headers['Pragma'] = 'no-cache'
    return response

