@app.route('/register', methods=['GET', 'POST'])
def register():
    if g.current_user:
        return redirect(url_for('dashboard'))
    
    if request.method == 'POST':
        if not validate_csrf_token():
            flash('Invalid request. Please try again.', 'error')
            return redirect(url_for('register'))
        
        # Rate limit registration
        if not check_rate_limit(f'register:{request.remote_addr}', max_requests=5, window=300):
            flash('Too many registration attempts. Please try again later.', 'error')
            return redirect(url_for('register'))
        
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        confirm_password = request.form.get('confirm_password', '')
        
        if password != confirm_password:
            flash('Passwords do not match.', 'error')
            return redirect(url_for('register'))
        
        success, message = register_user(username, password)
        if success:
            flash(message + ' Please log in.', 'success')
            return redirect(url_for('login'))
        else:
            flash(message, 'error')
            return redirect(url_for('register'))
    
    return render_template_string(
        BASE_TEMPLATE,
        title='Register',
        content=render_template_string(REGISTER_FORM),
        current_user=g.current_user
    )

@app.route('/login', methods=['GET', 'POST'])
def login():
    if g.current_user:
        return redirect(url_for('dashboard'))
    
    if request.method == 'POST':
        if not validate_csrf_token():
            flash('Invalid request. Please try again.', 'error')
            return redirect(url_for('login'))
        
        # Rate limit login attempts
        if not check_rate_limit(f'login:{request.remote_addr}', max_requests=10, window=60):
            flash('Too many login attempts. Please try again later.', 'error')
            return redirect(url_for('login'))
        
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        remember_me = request.form.get('remember_me') == 'on'
        
        success, error_message = authenticate_user(username, password)
        
        if success:
            # Regenerate session to prevent fixation
            session.clear()
            
            session_token = create_session(username.lower())
            session['session_token'] = session_token
            session['username'] = username.lower()
            
            if remember_me:
                session.permanent = True
                # Extend session lifetime for "remember me"
                SESSIONS_DB[session_token]['created_at'] = time.time()
            
            flash('Login successful!', 'success')
            
            # Redirect to next page or dashboard
            next_url = request.args.get('next')
            if next_url and next_url.startswith('/'):
                return redirect(next_url)
            return redirect(url_for('dashboard'))
        else:
            if error_message:
                flash(error_message, 'error')
            else:
                flash('Invalid username or password.', 'error')
            return redirect(url_for('login'))
    
    return render_template_string(
        BASE_TEMPLATE,
        title='Login',
        content=render_template_string(LOGIN_FORM),
        current_user=g.current_user
    )

@app.route('/logout')
@login_required
def logout():
    session_token = session.get('session_token')
    if session_token:
        destroy_session(session_token)
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('login'))

