@app.route('/sessions')
@login_required
def active_sessions():
    user_sessions = []
    current_token = session.get('session_token')
    
    for token, sess in SESSIONS_DB.items():
        if sess['user_id'] == g.current_user:
            is_current = (token == current_token)
            user_sessions.append({
                'token_prefix': token[:8] + '...',
                'created_at': time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(sess['created_at'])),
                'last_active': time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(sess['last_active'])),
                'ip_address': sess['ip_address'],
                'user_agent': sess['user_agent'][:80],
                'is_current': is_current
            })
    
    sessions_html = ""
    for s in user_sessions:
        current_badge = ' <strong>(current)</strong>' if s['is_current'] else ''
        sessions_html += f"""
        <div class="session-item">
            <p><strong>Session:</strong> {s['token_prefix']}{current_badge}</p>
            <p><strong>Created:</strong> {s['created_at']}</p>
            <p><strong>Last Active:</strong> {s['last_active']}</p>
            <p><strong>IP:</strong> {s['ip_address']}</p>
            <p><strong>Browser:</strong> {s['user_agent']}</p>
        </div>
        """
    
    content = f"""
    <p>You have <strong>{len(user_sessions)}</strong> active session(s).</p>
    {sessions_html}
    <form method="POST" action="{url_for('logout_all')}">
        <input type="hidden" name="_csrf_token" value="{generate_csrf_token()}">
        <button type="submit" class="danger">Logout All Sessions</button>
    </form>
    """
    
    return render_template_string(
        BASE_TEMPLATE,
        title='Active Sessions',
        content=content,
        current_user=g.current_user
    )

@app.route('/change-password', methods=['GET', 'POST'])
@login_required
def change_password():
    if request.method == 'POST':
        if not validate_csrf_token():
            flash('Invalid request.', 'error')
            return redirect(url_for('change_password'))
        
        current_password = request.form.get('current_password', '')
        new_password = request.form.get('new_password', '')
        confirm_password = request.form.get('confirm_password', '')
        
        if new_password != confirm_password:
            flash('New passwords do not match.', 'error')
            return redirect(url_for('change_password'))
        
        if len(new_password) < 8:
            flash('New password must be at least 8 characters.', 'error')
            return redirect(url_for('change_password'))
        
        user = USERS_DB.get(g.current_user)
        if not user:
            flash('User not found.', 'error')
            return redirect(url_for('login'))
        
        if not verify_password(current_password, user['salt'], user['password_hash']):
            flash('Current password is incorrect.', 'error')
            return redirect(url_for('change_password'))
        
        # Update password
        salt, password_hash = hash_password(new_password)
        user['salt'] = salt
        user['password_hash'] = password_hash
        
        # Invalidate all other sessions (keep current one)
        current_token = session.get('session_token')
        tokens_to_remove = [
            token for token, sess in SESSIONS_DB.items()
            if sess['user_id'] == g.current_user and token != current_token
        ]
        for token in tokens_to_remove:
            del SESSIONS_DB[token]
        
        flash('Password changed successfully. All other sessions have been terminated.', 'success')
        return redirect(url_for('dashboard'))
    
    return render_template_string(
        BASE_TEMPLATE,
        title='Change Password',
        content=render_template_string(CHANGE_PASSWORD_FORM),
        current_user=g.current_user
    )

